import{_ as t,o as a,c as s,ad as n}from"./chunks/framework.DdcUsuRQ.js";const u=JSON.parse('{"title":"Accessibility calculations","description":"How iridis measures and enforces contrast. WCAG 2.1 luminance ratios, APCA Lc magnitudes, and CVD simulation as swappable math primitives.","frontmatter":{"title":"Accessibility calculations","description":"How iridis measures and enforces contrast. WCAG 2.1 luminance ratios, APCA Lc magnitudes, and CVD simulation as swappable math primitives.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/concepts/accessibility-calculations"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/concepts/accessibility-calculations"}],["meta",{"property":"og:title","content":"Accessibility calculations: iridis"}],["meta",{"property":"og:description","content":"How iridis measures and enforces contrast. WCAG 2.1 luminance ratios, APCA Lc magnitudes, and CVD simulation as swappable math primitives."}],["meta",{"name":"twitter:title","content":"Accessibility calculations: iridis"}],["meta",{"name":"twitter:description","content":"How iridis measures and enforces contrast. WCAG 2.1 luminance ratios, APCA Lc magnitudes, and CVD simulation as swappable math primitives."}],["meta",{"name":"description","content":"How iridis measures and enforces contrast. WCAG 2.1 luminance ratios, APCA Lc magnitudes, and CVD simulation as swappable math primitives."}],["meta",{"property":"article:modified_time","content":"2026-05-18T14:11:40.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Concepts\\",\\"item\\":\\"https://studnicky.github.io/iridis/concepts\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Accessibility calculations\\",\\"item\\":\\"https://studnicky.github.io/iridis/concepts/accessibility-calculations\\"}]}"]]},"headers":[],"relativePath":"concepts/accessibility-calculations.md","filePath":"concepts/accessibility-calculations.md","lastUpdated":1779113500000}'),r={name:"concepts/accessibility-calculations.md"};function e(o,i,d,c,l,p){return a(),s("div",null,[...i[0]||(i[0]=[n('<h1 id="accessibility-calculations" tabindex="-1">Accessibility calculations <a class="header-anchor" href="#accessibility-calculations" aria-label="Permalink to &quot;Accessibility calculations&quot;">​</a></h1><p><span class="iridis-brand">iridis</span> treats accessibility as a constraint the engine satisfies, not an afterthought you audit. Three layers do the work: contrast measurement, contrast enforcement, and CVD simulation. Each is a registered math primitive, swap or extend without touching task code.</p><div class="tip custom-block"><p class="custom-block-title">Live demo</p><p>Toggle <strong>Contrast level</strong> and <strong>Contrast algorithm</strong> in the sidebar config to see <code>enforce:contrast</code> lift role pairs to the selected threshold in real time. The chip you see is the chip your users get.</p></div><h2 id="wcag-2-1-contrast-contrastwcag21" tabindex="-1">WCAG 2.1 contrast, <code>contrastWcag21</code> <a class="header-anchor" href="#wcag-2-1-contrast-contrastwcag21" aria-label="Permalink to &quot;WCAG 2.1 contrast, `contrastWcag21`&quot;">​</a></h2><p>The web&#39;s incumbent metric. Computes a luminance ratio <code>(L₁ + 0.05) / (L₂ + 0.05)</code> where <code>L₁ ≥ L₂</code>, against gamma-decoded sRGB primaries. The result is unitless and ranges 1.0 (no contrast) to 21.0 (white on black).</p><table tabindex="0"><thead><tr><th>Tier</th><th>Ratio</th><th>Use</th></tr></thead><tbody><tr><td>AA</td><td>≥ 4.5</td><td>Body text</td></tr><tr><td>AA Large</td><td>≥ 3.0</td><td>18pt+ regular or 14pt+ bold</td></tr><tr><td>AAA</td><td>≥ 7.0</td><td>High-stakes body text</td></tr><tr><td>Non-text</td><td>≥ 3.0</td><td>UI components, focus rings</td></tr></tbody></table><p>Strengths: ubiquitous, legally cited, easy to reason about. Weaknesses: model is a 1990s simplification, it underweights blue-on-black and overweights bright on white.</p><h2 id="apca-contrastapca" tabindex="-1">APCA, <code>contrastApca</code> <a class="header-anchor" href="#apca-contrastapca" aria-label="Permalink to &quot;APCA, `contrastApca`&quot;">​</a></h2><p>The Advanced Perceptual Contrast Algorithm under development for WCAG 3. Models polarity (light-on-dark vs dark-on-light), uses a perceptual lightness curve closer to OKLCH, and produces a signed value <code>Lc</code> in roughly <code>[-108, +108]</code>.</p><table tabindex="0"><thead><tr><th>Use</th><th>Lc threshold</th></tr></thead><tbody><tr><td>Body text</td><td>≥ 75</td></tr><tr><td>Large copy</td><td>≥ 60</td></tr><tr><td>Non-text UI</td><td>≥ 45</td></tr><tr><td>Spot text</td><td>≥ 30</td></tr></tbody></table><p><span class="iridis-brand">iridis</span> exposes both. Pick the algorithm in <code>input.contrast.algorithm</code>. Plugins targeting the same threshold value get different behavior under each, APCA is stricter on dark-on-dark, more permissive on saturated-on-light.</p><h2 id="contrastpairs-declaring-intent" tabindex="-1"><code>contrastPairs</code>, declaring intent <a class="header-anchor" href="#contrastpairs-declaring-intent" aria-label="Permalink to &quot;`contrastPairs`, declaring intent&quot;">​</a></h2><p>A role schema declares its accessibility requirements as a list of <code>contrastPairs</code>. Each pair names the foreground role, the background role, the minimum ratio (or Lc), and optionally an explicit algorithm.</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">export</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);"> const</span><span style="--shiki-light:var(--iridis-syntax-constant);--shiki-dark:var(--iridis-syntax-constant);"> mySchema</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">:</span><span style="--shiki-light:var(--iridis-syntax-function);--shiki-dark:var(--iridis-syntax-function);"> RoleSchemaInterface</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);"> =</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> {</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);">  name</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);">  &#39;my-palette&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);">  roles</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> [</span><span style="--shiki-light:var(--iridis-syntax-comment);--shiki-dark:var(--iridis-syntax-comment);"> /* ... */</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> ],</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);">  contrastPairs</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> [</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">    {</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> foreground</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;text&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);">     background</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;canvas&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> minRatio</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-number);--shiki-dark:var(--iridis-syntax-number);"> 4</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">.</span><span style="--shiki-light:var(--iridis-syntax-number);--shiki-dark:var(--iridis-syntax-number);">5</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> algorithm</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;wcag21&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> },</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">    {</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> foreground</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;onAccent&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> background</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;accent&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> minRatio</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-number);--shiki-dark:var(--iridis-syntax-number);"> 4</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">.</span><span style="--shiki-light:var(--iridis-syntax-number);--shiki-dark:var(--iridis-syntax-number);">5</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> algorithm</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;wcag21&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> },</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">    {</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> foreground</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;border&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);">   background</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;canvas&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> minRatio</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-number);--shiki-dark:var(--iridis-syntax-number);"> 3</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">.</span><span style="--shiki-light:var(--iridis-syntax-number);--shiki-dark:var(--iridis-syntax-number);">0</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> algorithm</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;wcag21&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> },</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">  ],</span></span>\n<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">};</span></span></code></pre></div><p>Pairs are not opt-in. Every pair you declare is a hard contract, <code>enforce:contrast</code> will adjust foreground roles until the ratio is satisfied.</p><h2 id="enforce-contrast-the-nudge-loop" tabindex="-1"><code>enforce:contrast</code>, the nudge loop <a class="header-anchor" href="#enforce-contrast-the-nudge-loop" aria-label="Permalink to &quot;`enforce:contrast`, the nudge loop&quot;">​</a></h2><p>Built on <code>ensureContrast</code>, this task walks every declared pair after <code>resolve:roles</code> has assigned candidates. For each pair below threshold:</p><ol><li>Compare foreground and background lightness.</li><li>Pick a step direction in OKLCH: push foreground darker (if lighter than bg) or lighter (if darker).</li><li>Step by <code>0.02</code> lightness, recompute, recheck.</li><li>Bail at 50 iterations or when L hits the [0, 1] clamp.</li></ol><p>Hue and chroma are preserved. The result is a foreground that <em>looks the same</em> as the input but reads against the background. Combined with the role&#39;s declared <code>lightnessRange</code>, the task respects both the design constraint and the accessibility constraint, a contradiction surfaces as a reachable-extremum, not silent failure.</p><h2 id="cvd-simulation-brettel-vienot" tabindex="-1">CVD simulation, Brettel-Viénot <a class="header-anchor" href="#cvd-simulation-brettel-vienot" aria-label="Permalink to &quot;CVD simulation, Brettel-Viénot&quot;">​</a></h2><p>The <code>iridis-contrast</code> plugin (separate package) ships the <code>enforce:cvdSimulate</code> task. It applies four CVD transforms (<code>protanopia</code>, <code>deuteranopia</code>, <code>tritanopia</code>, <code>achromatopsia</code>) via the Brettel-Viénot matrices in linear sRGB, recomputes WCAG luminance contrast against each simulated pair, and writes warnings to <code>state.metadata[&#39;contrast:cvd&#39;]?.warnings</code> when the simulated ratio drops more than the per-type stability threshold below the original (or when the simulated contrast falls below the per-type floor).</p><p>Each warning entry includes <code>foreground</code>, <code>background</code>, <code>cvdType</code>, <code>originalLuminanceContrast</code>, <code>simulatedLuminanceContrast</code>, <code>drop</code>, <code>dropThreshold</code>, and <code>minSimulatedContrast</code> so a CI gate can audit which signal fired without cross-referencing the threshold table (sourced from <code>CVD_THRESHOLDS</code> in <code>packages/contrast/src/data/cvdThresholds.ts</code>).</p><p>CVD simulation is advisory: it surfaces palette pairs that collapse under simulation but does not modify <code>state.roles</code>. The hue-selection decision stays yours. The plugin is opt-in; the core engine ships only the WCAG and APCA metrics.</p><h2 id="why-declare-instead-of-validate" tabindex="-1">Why declare instead of validate <a class="header-anchor" href="#why-declare-instead-of-validate" aria-label="Permalink to &quot;Why declare instead of validate&quot;">​</a></h2><p>Most palette tools generate first, audit second. <span class="iridis-brand">iridis</span> flips it: you declare what must be true, the engine produces output that is already true. There is no &quot;accessibility report&quot; because there is no version of the palette that fails. The contract is the schema.</p><p>If a pair cannot be satisfied, for instance, a foreground locked into a narrow lightness range that cannot meet 7:1 against a likewise-narrow background, <code>enforce:contrast</code> produces the closest reachable approximation and records the remaining gap in <code>state.metadata[&#39;contrastShortfalls&#39;]</code>. You see the conflict at run time, in code, not three sprints after launch in a Jira ticket.</p>',26)])])}const y=t(r,[["render",e]]);export{u as __pageData,y as default};
